-- =====================================================================
-- V7__location_schema.sql
-- Division politica: Pais > Departamento > Municipio > Barrio/Vereda.
-- Seed: Colombia completa (DANE) + paises base + sample de barrios.
-- =====================================================================

SET @now = NOW(6);

-- ---------------------------------------------------------------------
-- LIMPIEZA DEFENSIVA: si una corrida previa fallo a mitad y dejo tablas
-- huerfanas (Flyway las marca success=false en history; el FlywayConfig
-- ya hace repair, pero los CREATE TABLE chocarian con las tablas
-- residuales). DROP en orden inverso por las FKs.
-- ---------------------------------------------------------------------
DROP TABLE IF EXISTS neighborhood;
DROP TABLE IF EXISTS municipality;
DROP TABLE IF EXISTS department;
DROP TABLE IF EXISTS country;

-- ---------------------------------------------------------------------
-- TABLAS
-- ---------------------------------------------------------------------

CREATE TABLE country (
    Id              CHAR(36)     NOT NULL,
    Code            VARCHAR(16)  NOT NULL,
    Name            VARCHAR(160) NOT NULL,
    OfficialName    VARCHAR(255) NULL,
    IsoCode3        VARCHAR(16)  NULL,
    NumericCode     VARCHAR(16)  NULL,
    PhoneCode       VARCHAR(16)  NULL,
    CurrencyCode    VARCHAR(16)  NULL,
    CurrencySymbol  VARCHAR(16)  NULL,
    Continent       VARCHAR(64)  NULL,
    Enabled         BOOLEAN      NOT NULL DEFAULT TRUE,
    Visible         BOOLEAN      NOT NULL DEFAULT TRUE,
    AuditUser       CHAR(36)     NULL,
    AuditDate       DATETIME(6)  NOT NULL,
    CreatedDate     DATETIME(6)  NOT NULL,
    PRIMARY KEY (Id),
    UNIQUE KEY uq_country_code (Code)
) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

CREATE TABLE department (
    Id           CHAR(36)     NOT NULL,
    Code         VARCHAR(32)  NOT NULL,
    Name         VARCHAR(160) NOT NULL,
    CountryId    CHAR(36)     NOT NULL,
    Enabled      BOOLEAN      NOT NULL DEFAULT TRUE,
    Visible      BOOLEAN      NOT NULL DEFAULT TRUE,
    AuditUser    CHAR(36)     NULL,
    AuditDate    DATETIME(6)  NOT NULL,
    CreatedDate  DATETIME(6)  NOT NULL,
    PRIMARY KEY (Id),
    UNIQUE KEY uq_department_country_code (CountryId, Code),
    KEY idx_department_country (CountryId),
    KEY idx_department_name (Name),
    CONSTRAINT fk_department_country FOREIGN KEY (CountryId) REFERENCES country (Id)
) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

CREATE TABLE municipality (
    Id           CHAR(36)     NOT NULL,
    Code         VARCHAR(32)  NOT NULL,
    Name         VARCHAR(160) NOT NULL,
    DepartmentId CHAR(36)     NOT NULL,
    Enabled      BOOLEAN      NOT NULL DEFAULT TRUE,
    Visible      BOOLEAN      NOT NULL DEFAULT TRUE,
    AuditUser    CHAR(36)     NULL,
    AuditDate    DATETIME(6)  NOT NULL,
    CreatedDate  DATETIME(6)  NOT NULL,
    PRIMARY KEY (Id),
    UNIQUE KEY uq_municipality_dept_code (DepartmentId, Code),
    KEY idx_municipality_dept (DepartmentId),
    KEY idx_municipality_name (Name),
    CONSTRAINT fk_municipality_department FOREIGN KEY (DepartmentId) REFERENCES department (Id)
) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

CREATE TABLE neighborhood (
    Id              CHAR(36)     NOT NULL,
    Code            VARCHAR(64)  NOT NULL,
    Name            VARCHAR(200) NOT NULL,
    Type            VARCHAR(32)  NOT NULL,
    MunicipalityId  CHAR(36)     NOT NULL,
    Enabled         BOOLEAN      NOT NULL DEFAULT TRUE,
    Visible         BOOLEAN      NOT NULL DEFAULT TRUE,
    AuditUser       CHAR(36)     NULL,
    AuditDate       DATETIME(6)  NOT NULL,
    CreatedDate     DATETIME(6)  NOT NULL,
    PRIMARY KEY (Id),
    UNIQUE KEY uq_neighborhood_muni_code (MunicipalityId, Code),
    KEY idx_neighborhood_muni (MunicipalityId),
    KEY idx_neighborhood_name (Name),
    KEY idx_neighborhood_type (Type),
    CONSTRAINT fk_neighborhood_municipality FOREIGN KEY (MunicipalityId) REFERENCES municipality (Id)
) ENGINE = InnoDB DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

